return ['x-generator'=>'GlotPress/4.0.0-rc.1','translation-revision-date'=>'2025-03-19 09:26:04+0000','plural-forms'=>'nplurals=2; plural=n != 1;','project-id-version'=>'RocketGenius - Gravity Forms reCAPTCHA','language'=>'de','messages'=>['You have reached the quota limit for reCAPTCHA set by Google. Please check the quota on your %sreCAPTCHA Account%s.'=>'Du hast die von Google festgelegte Quotengrenze für reCAPTCHA erreicht. Bitte überprüfe die Quote auf deinem %sreCAPTCHA-Konto%s.','Value defined using the %s constant.'=>'Wert, der mit der Konstante %s definiert wurde.','Click here to learn more about reCAPTCHA.'=>'Hier klicken, um mehr über reCAPTCHA zu erfahren.','Score'=>'Punktzahl','reCAPTCHA'=>'reCAPTCHA','reCAPTCHA Score'=>'reCAPTCHA-Punktzahl','Disable reCAPTCHA v3 for this form.'=>'reCAPTCHA v3 für dieses Formular deaktivieren.','Score threshold must be between 0.0 and 1.0'=>'Punktzahl-Schwellenwert muss zwischen 0.0 und 1.0 liegen','Unexpected field type.'=>'Unerwarteter Feldtyp.','The default threshold is 0.5.'=>'Der Standard-Schwellenwert ist 0.5.','If the score is less than or equal to this threshold, the form submission will be sent to spam.'=>'Falls die Punktzahl kleiner oder gleich des Schwellenwertes ist, wird die Formularübermittlung als Spam betrachtet.','reCAPTCHA v3 returns a score (1.0 is very likely a good interaction, 0.0 is very likely a bot).'=>'reCAPTCHA v3 gibt eine Punktzahl zurück (1.0 ist sehr wahrscheinlich eine gute Interaktion, 0.0 ist sehr wahrscheinlich ein Bot).','check out our documentation.'=>'lies unsere Dokumentation.','For more information on reCAPTCHA, which version is right for you, and how to add it to your forms,'=>'Für weitere Informationen über reCAPTCHA, welche Version die richtige für dich ist und wie du es deinen Formularen hinzufügst,','reCAPTCHA v2 (Checkbox) - Requires a user to click a checkbox to indicate that they are not a robot and displays a challenge if the activity is suspicious'=>'reCAPTCHA v2 (Kontrollkästchen) - Erfordert einen Klick des Benutzers, um anzuzeigen, dass sie kein Roboter sind und zeigt eine Herausforderung an, falls die Aktivität verdächtig erscheint','Read more about reCAPTCHA.'=>'Mehr über reCAPTCHA erfahren.','To activate reCAPTCHA v2 on your form, simply add the CAPTCHA field in the form editor.'=>'Um reCAPTCHA v2 für dein Formular zu aktivieren, füge einfach das CAPTCHA-Feld im Formulareditor hinzu.','Please note, only v2 keys are supported and checkbox keys are not compatible with invisible reCAPTCHA.'=>'Bitte bedenke, dass nur  v2-Schlüssel unterstützt werden und Auswahlkästchen-Schlüssel nicht mit unsichtbarem reCAPTCHA kompatibel sind.','reCAPTCHA v2 (Invisible) - Displays a badge on your form and will present a challenge to the user if the activity is suspicious e.g. select the traffic lights.'=>'reCAPTCHA v2 (unsichtbar) - Zeigt ein Abzeichen auf deinem Formular an und wird dem Benutzer eine Herausforderung präsentieren, falls die Aktivität verdächtig ist, z.&nbsp;B. Ampeln auswählen.','When reCAPTCHA v3 is configured, it is enabled automatically on all forms by default. It can be disabled for specific forms in the form settings.'=>'Wenn reCAPTCHA v3 konfiguriert ist, wird es automatisch standardmäßig für alle Formulare aktiviert. Es kann in den Formular-Einstellungen für bestimmte Formulare deaktiviert werden.','All submissions are accepted and suspicious submissions are marked as spam.'=>'Alle Einreichungen werden akzeptiert und verdächtige Einreichungen werden als Spam gekennzeichnet.','reCAPTCHA v3 - Adds a script to every page of your site and uploads form content for processing by Google.'=>'reCAPTCHA v3 - Fügt jeder Seite ein Skript hinzu und lädt Formularinhalte hoch, damit sie von Google verarbeitet werden.','Gravity Forms integrates with three types of Google reCAPTCHA.'=>'Gravity Forms integriert 3 Typen von Google reCAPTCHA.','By adding reCAPTCHA to your forms, you can deter automated software from submitting form entries, while still ensuring a user-friendly experience for real people.'=>'Mit dem Hinzufügen von reCAPTCHA zu deinen Formularen kannst du automatische Software daran hindern, Formulareinträge zu machen, während du trotzdem eine benutzerfreundliche Erfahrung für echte Menschen sicherstellst.','Google reCAPTCHA is a free anti-spam service that protects your website from fraud and abuse.'=>'Google reCAPTCHA ist ein kostenloser Anti-Spam-Dienst, der deine Website vor Betrug und Missbrauch schützt.','reCAPTCHA keys are invalid.'=>'reCAPTCHA-Schlüssel sind ungültig.','Validate Keys'=>'Schlüssel validieren','Invisible'=>'Unsichtbar','Checkbox'=>'Kontrollkästchen','Type'=>'Typ','reCAPTCHA v2'=>'reCAPTCHA v2','I have added the reCAPTCHA branding, terms of service and privacy policy to my site. '=>'Ich habe meiner Website das reCAPTCHA-Branding, Nutzungsbedingungen und die Datenschutzbestimmungen hinzugefügt.','By default reCAPTCHA v3 displays a badge on every page of your site with links to the Google terms of service and privacy policy. You are allowed to hide the badge as long as you include the reCAPTCHA branding and links visibly in the user flow.'=>'Standardmäßig zeigt reCAPTCHA v3 ein Abzeichen mit Links zu den Nutzungsbedingungen von Google und den Datenschutzbestimmungen auf jeder Seite deiner Website an. Du darfst das Abzeichen verbergen, solange du das reCAPTCHA-Branding und Links sichtbar im Benutzerablauf einbaust.','Disable Google reCAPTCHA Badge'=>'Google reCAPTCHA Badge verbergen','Score Threshold'=>'Punktzahl-Schwellenwert','Secret Key'=>'Geheimer Schlüssel','Site Key'=>'Website Schlüssel','reCAPTCHA Settings'=>'reCAPTCHA Einstellungen','Gravity Forms'=>'Gravity Forms','Enhance Gravity Forms with support for Google reCAPTCHA.'=>'Erweitere Gravity Forms mit Unterstützung für Google reCAPTCHA.','https://gravityforms.com'=>'https://gravityforms.com','Gravity Forms reCAPTCHA Add-On'=>'Gravity Forms reCAPTCHA Add-On']];